    sample_rate = 44100
    duration = 1.2
    frames = int(sample_rate * duration)
    t = np.linspace(0, duration, frames, False)

    freq = np.linspace(800, 50, frames)
    wave = np.sin(2 * np.pi * freq * t)

    # Add some harmonics
