    sample_rate = 44100
    duration = 0.3
    frames = int(sample_rate * duration)
    t = np.linspace(0, duration, frames, False)

    # Rising arpeggio
    freqs = [261, 329, 392, 523]
    wave = np.zeros(frames)
    seg = frames // len(freqs)
    for i, f in enumerate(freqs):
        start = i * seg
