class Particle:
    def __init__(self, x, y, color):
        self.x = x
        self.y = y
        self.vx = random.uniform(-3, 3)
        self.vy = random.uniform(-3, 3)
        self.life = 1.0
        self.color = color
        self.size = random.randint(2, 5)

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.1
        self.life -= 0.05
        return self.life > 0

    def draw(self, surface):
        alpha = int(self.life * 255)
        color = (*self.color[:3], alpha)
        size = max(1, int(self.size * self.life))
        pygame.draw.circle(surface, self.color[:3], (int(self.x), int(self.y)), size)


class PacMan:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.pixel_x = x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
        self.pixel_y = y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
        self.direction = (1, 0)
        self.next_direction = (1, 0)
        self.mouth_angle = 45
        self.mouth_opening = True
        self.speed = 2.5
        self.moving = False
        self.lives = 3
        self.score = 0
        self.animation_timer = 0
        self.death_animation = 0
        self.is_dying = False
        self.waka_timer = 0

    def draw(self, surface):
        if self.is_dying:
            # Death animation - pacman closes
            angle = self.death_animation * 180
            if angle < 360:
                start_angle = math.radians(angle / 2)
                end_angle = math.radians(360 - angle / 2)
                if start_angle < end_angle:
                    # Draw pacman body
                    pygame.draw.circle(surface, YELLOW, (int(self.pixel_x), int(self.pixel_y)), CELL_SIZE // 2 - 2)
                    # Draw black wedge for mouth
                    points = [(int(self.pixel_x), int(self.pixel_y))]
                    for a in range(int(math.degrees(start_angle)), int(math.degrees(end_angle)) + 1, 5):
                        rad = math.radians(a)
                        px = self.pixel_x + (CELL_SIZE // 2) * math.cos(rad)
                        py = self.pixel_y + (CELL_SIZE // 2) * math.sin(rad)
                        points.append((int(px), int(py)))
                    if len(points) > 2:
                        pygame.draw.polygon(surface, BLACK, points)
            return

        # Normal drawing
        # Glow effect
        glow_surf = pygame.Surface((CELL_SIZE * 2, CELL_SIZE * 2), pygame.SRCALPHA)
        pygame.draw.circle(glow_surf, (255, 255, 0, 30), (CELL_SIZE, CELL_SIZE), CELL_SIZE - 1)
        surface.blit(glow_surf, (int(self.pixel_x) - CELL_SIZE, int(self.pixel_y) - CELL_SIZE))

        # Calculate mouth angle based on direction
        dir_angle = math.degrees(math.atan2(self.direction[1], self.direction[0]))

        mouth = self.mouth_angle
        start_angle = dir_angle + mouth
        end_angle = dir_angle - mouth + 360

        # Draw pacman
        radius = CELL_SIZE // 2 - 2

        # Body
        pygame.draw.circle(surface, YELLOW, (int(self.pixel_x), int(self.pixel_y)), radius)

        # Mouth (black wedge)
        if mouth > 2:
            points = [(int(self.pixel_x), int(self.pixel_y))]
            start_rad = math.radians(start_angle)
            end_rad = math.radians(end_angle % 360)

            # Draw the mouth wedge
            for a in range(int(start_angle), int(start_angle + mouth * 2) + 1, 3):
                rad = math.radians(a)
                px = self.pixel_x + radius * math.cos(rad)
                py = self.pixel_y + radius * math.sin(rad)
                points.append((int(px), int(py)))

            if len(points) > 2:
                pygame.draw.polygon(surface, BLACK, points)

        # Eye
        eye_angle = math.radians(dir_angle - 60)
        eye_x = self.pixel_x + (radius * 0.5) * math.cos(eye_angle)
        eye_y = self.pixel_y + (radius * 0.5) * math.sin(eye_angle)
        pygame.draw.circle(surface, BLACK, (int(eye_x), int(eye_y)), 2)

    def animate(self):
        self.animation_timer += 1
        if self.animation_timer % 3 == 0:
            if self.mouth_opening:
                self.mouth_angle -= 5
                if self.mouth_angle <= 5:
                    self.mouth_opening = False
            else:
                self.mouth_angle += 5
                if self.mouth_angle >= 45:
                    self.mouth_opening = True


class Ghost:
    COLORS = [RED, PINK, CYAN, ORANGE]
    NAMES = ['Blinky', 'Pinky', 'Inky', 'Clyde']

    def __init__(self, x, y, ghost_id):
        self.start_x = x
        self.start_y = y
        self.x = x
        self.y = y
        self.pixel_x = x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
        self.pixel_y = y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
        self.ghost_id = ghost_id
        self.color = self.COLORS[ghost_id % 4]
        self.direction = random.choice([(0, -1), (0, 1), (-1, 0), (1, 0)])
        self.speed = 2.0
        self.scared = False
        self.scared_timer = 0
        self.eaten = False
        self.animation_timer = 0
        self.wave_offset = ghost_id * 0.5
        self.release_timer = ghost_id * 60  # Stagger ghost releases
        self.in_house = ghost_id > 0
        self.eye_offset = [0, 0]

    def draw(self, surface):
        if self.eaten:
            # Draw eyes only
            self._draw_eyes(surface, WHITE)
            return

        radius = CELL_SIZE // 2 - 3

        if self.scared:
            # Flashing when scared timer is low
            if self.scared_timer < 120 and (self.scared_timer // 15) % 2 == 0:
                body_color = SCARED_WHITE
            else:
                body_color = SCARED_BLUE
        else:
            body_color = self.color

        # Glow effect
        glow_surf = pygame.Surface((CELL_SIZE * 2, CELL_SIZE * 2), pygame.SRCALPHA)
        glow_color = (*body_color, 20)
        pygame.draw.circle(glow_surf, glow_color, (CELL_SIZE, CELL_SIZE), CELL_SIZE)
        surface.blit(glow_surf, (int(self.pixel_x) - CELL_SIZE, int(self.pixel_y) - CELL_SIZE))

        # Ghost body - rounded top
        body_rect = pygame.Rect(int(self.pixel_x) - radius, int(self.pixel_y) - radius,
                                radius * 2, radius * 2)
        pygame.draw.circle(surface, body_color, (int(self.pixel_x), int(self.pixel_y) - 2), radius)
        pygame.draw.rect(surface, body_color,
                         (int(self.pixel_x) - radius, int(self.pixel_y) - 2, radius * 2, radius))

        # Wavy bottom
        wave_y = int(self.pixel_y) + radius - 2
        wave_points = []
        num_waves = 3
        wave_width = radius * 2 / num_waves

        wave_anim = math.sin(self.animation_timer * 0.2 + self.wave_offset) * 2

        wave_points.append((int(self.pixel_x) - radius, wave_y))
        for i in range(num_waves):
            x1 = int(self.pixel_x) - radius + i * wave_width
            x2 = x1 + wave_width / 2
            x3 = x1 + wave_width
            wave_points.append((int(x2), wave_y - 4 + wave_anim))
            wave_points.append((int(x3), wave_y))
        wave_points.append((int(self.pixel_x) + radius, wave_y + 2))
        wave_points.append((int(self.pixel_x) - radius, wave_y + 2))

        if len(wave_points) > 2:
            pygame.draw.polygon(surface, body_color, wave_points)

        # Eyes
        if not self.scared:
            self._draw_eyes(surface, WHITE)
        else:
            # Scared face
            eye_y = int(self.pixel_y) - 3
            pygame.draw.circle(surface, WHITE, (int(self.pixel_x) - 4, eye_y), 2)
            pygame.draw.circle(surface, WHITE, (int(self.pixel_x) + 4, eye_y), 2)
            # Wavy mouth
            for i in range(-4, 5, 2):
                my = eye_y + 6 + (2 if i % 4 == 0 else -2)
                pygame.draw.circle(surface, WHITE, (int(self.pixel_x) + i, my), 1)

    def _draw_eyes(self, surface, white_color):
        # Eye whites
        pygame.draw.circle(surface, white_color, (int(self.pixel_x) - 4, int(self.pixel_y) - 3), 4)
        pygame.draw.circle(surface, white_color, (int(self.pixel_x) + 4, int(self.pixel_y) - 3), 4)

        # Pupils (follow direction)
        pupil_color = (0, 0, 200)
        dx = self.direction[0] * 1.5
        dy = self.direction[1] * 1.5
        pygame.draw.circle(surface, pupil_color,
                           (int(self.pixel_x) - 4 + int(dx), int(self.pixel_y) - 3 + int(dy)), 2)
        pygame.draw.circle(surface, pupil_color,
                           (int(self.pixel_x) + 4 + int(dx), int(self.pixel_y) - 3 + int(dy)), 2)

    def animate(self):
        self.animation_timer += 1
        if self.scared and self.scared_timer > 0:
            self.scared_timer -= 1
            if self.scared_timer <= 0:
                self.scared = False


class Game:
    def __init__(self):
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("PAC-MAN")
        self.clock = pygame.time.Clock()
        self.font_large = pygame.font.Font(None, 72)
        self.font_medium = pygame.font.Font(None, 48)
        self.font_small = pygame.font.Font(None, 32)
        self.font_tiny = pygame.font.Font(None, 24)

        self.state = 'start'  # start, playing, dying, game_over, win
        self.particles = []
        self.score_popups = []
        self.frame = 0
        self.high_score = 0

        self.reset_game()
        print("Game initialized!")

    def reset_game(self):
        # Copy maze
        self.maze = [row[:] for row in MAZE]

        # Count total dots
        self.total_dots = sum(1 for row in self.maze for cell in row if cell in [0, 2])
        self.dots_eaten = 0

        # Create pacman
        self.pacman = PacMan(9, 16)

        # Create ghosts
        self.ghosts = [
            Ghost(9, 9, 0),  # Blinky - red
            Ghost(8, 11, 1),  # Pinky
            Ghost(9, 11, 2),  # Inky
            Ghost(10, 11, 3),  # Clyde
        ]

        self.power_mode = False
        self.power_timer = 0
        self.ghosts_eaten_combo = 0
        self.death_timer = 0
        self.start_timer = 180

    def reset_positions(self):
        self.pacman.x = 9
        self.pacman.y = 16
        self.pacman.pixel_x = 9 * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
        self.pacman.pixel_y = 16 * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
        self.pacman.direction = (1, 0)
        self.pacman.next_direction = (1, 0)
        self.pacman.is_dying = False
        self.pacman.death_animation = 0

        for i, ghost in enumerate(self.ghosts):
            ghost.x = ghost.start_x
            ghost.y = ghost.start_y
            ghost.pixel_x = ghost.start_x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
            ghost.pixel_y = ghost.start_y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
            ghost.scared = False
            ghost.eaten = False
            ghost.in_house = i > 0
            ghost.release_timer = i * 60

        self.power_mode = False
        self.power_timer = 0
        self.start_timer = 120

    def can_move(self, x, y):
        if x < 0 or x >= COLS or y < 0 or y >= ROWS:
            return True  # Tunnel
        return self.maze[y][x] != 1

    def can_ghost_move(self, x, y):
        if x < 0 or x >= COLS or y < 0 or y >= ROWS:
            return False
        return self.maze[y][x] != 1

    def move_pacman(self):
        pac = self.pacman

        # Try next direction first
        nx = pac.x + pac.next_direction[0]
        ny = pac.y + pac.next_direction[1]

        # Handle tunnel
        nx = nx % COLS

        if self.can_move(nx, ny):
            pac.direction = pac.next_direction

        # Move in current direction
        nx = (pac.x + pac.direction[0]) % COLS
        ny = pac.y + pac.direction[1]

        if self.can_move(nx, ny):
            pac.x = nx
            pac.y = ny
            pac.pixel_x = pac.x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
            pac.pixel_y = pac.y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
            pac.moving = True

            # Check for dot eating
            if 0 <= pac.y < ROWS and 0 <= pac.x < COLS:
                cell = self.maze[pac.y][pac.x]
                if cell == 0:  # Regular dot
                    self.maze[pac.y][pac.x] = 3
                    self.pacman.score += 10
                    self.dots_eaten += 1

                    # Play waka sound
                    pac.waka_timer += 1
                    if pac.waka_timer % 2 == 0 and WAKA_SOUND:
                        WAKA_SOUND.play()

                    # Dot particles
                    px = pac.x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
                    py = pac.y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
                    for _ in range(3):
                        self.particles.append(Particle(px, py, YELLOW))

                elif cell == 2:  # Power pellet
                    self.maze[pac.y][pac.x] = 3
                    self.pacman.score += 50
                    self.dots_eaten += 1
                    self.power_mode = True
                    self.power_timer = 400
                    self.ghosts_eaten_combo = 0

                    if POWER_SOUND:
                        POWER_SOUND.play()

                    # Make ghosts scared
                    for ghost in self.ghosts:
                        if not ghost.eaten:
                            ghost.scared = True
                            ghost.scared_timer = 400

                    # Big particles
                    px = pac.x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
                    py = pac.y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y
                    for _ in range(15):
                        self.particles.append(Particle(px, py, GOLD))
        else:
            pac.moving = False

    def move_ghost(self, ghost):
        if ghost.in_house:
            if ghost.release_timer > 0:
                ghost.release_timer -= 1
                # Bounce in house
                ghost.pixel_y += math.sin(self.frame * 0.1 + ghost.ghost_id) * 0.5
                return
            else:
                ghost.in_house = False
                ghost.y = 8  # Exit house
                ghost.x = 9
                ghost.pixel_x = ghost.x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
                ghost.pixel_y = ghost.y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y

        # Get possible directions
        possible = []
        for dx, dy in [(0, -1), (0, 1), (-1, 0), (1, 0)]:
            # Don't reverse direction
            if dx == -ghost.direction[0] and dy == -ghost.direction[1]:
                continue
            nx = ghost.x + dx
            ny = ghost.y + dy
            if self.can_ghost_move(nx, ny):
                possible.append((dx, dy))

        if not possible:
            # Reverse
            ghost.direction = (-ghost.direction[0], -ghost.direction[1])
            possible = [ghost.direction]

        # Choose direction
        if len(possible) > 1:
            if ghost.scared:
                # Random movement when scared
                ghost.direction = random.choice(possible)
            else:
                # Chase pacman (simplified)
                pac_x = self.pacman.x
                pac_y = self.pacman.y

                best_dir = possible[0]
                best_dist = float('inf')

                for dx, dy in possible:
                    nx = ghost.x + dx
                    ny = ghost.y + dy
                    dist = (nx - pac_x) ** 2 + (ny - pac_y) ** 2

                    # Add some randomness
                    dist += random.uniform(-5, 5)

                    if dist < best_dist:
                        best_dist = dist
                        best_dir = (dx, dy)

                ghost.direction = best_dir
        elif possible:
            ghost.direction = possible[0]

        # Move ghost
        speed = ghost.speed * (0.7 if ghost.scared else 1.0)
        if ghost.eaten:
            speed = ghost.speed * 2

        ghost.x += ghost.direction[0]
        ghost.y += ghost.direction[1]
        ghost.pixel_x = ghost.x * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_X
        ghost.pixel_y = ghost.y * CELL_SIZE + CELL_SIZE // 2 + MAZE_OFFSET_Y

        # Check if eaten ghost returned home
        if ghost.eaten and abs(ghost.x - ghost.start_x) <= 1 and abs(ghost.y - ghost.start_y) <= 1:
            ghost.eaten = False
            ghost.scared = False
            ghost.in_house = False

    def check_collisions(self):
        pac = self.pacman

        for ghost in self.ghosts:
            if ghost.eaten:
                continue

            dist = abs(pac.x - ghost.x) + abs(pac.y - ghost.y)

            if dist <= 1:
                if ghost.scared:
                    # Eat ghost
                    ghost.eaten = True
                    ghost.scared = False
                    self.ghosts_eaten_combo += 1
                    points = 200 * (2 ** (self.ghosts_eaten_combo - 1))
                    pac.score += points

                    if GHOST_EAT_SOUND:
                        GHOST_EAT_SOUND.play()

                    # Score popup
                    self.score_popups.append({
                        'text': str(points),
                        'x': ghost.pixel_x,
                        'y': ghost.pixel_y,
                        'timer': 60,
                        'color': CYAN
                    })

                    # Particles
                    for _ in range(20):
                        self.particles.append(Particle(ghost.pixel_x, ghost.pixel_y, ghost.color))

                elif not self.power_mode:
                    # Pacman dies
                    pac.lives -= 1
                    if DEATH_SOUND:
                        DEATH_SOUND.play()

                    pac.is_dying = True
                    self.state = 'dying'
                    self.death_timer = 120

                    # Death particles
                    for _ in range(30):
                        self.particles.append(Particle(pac.pixel_x, pac.pixel_y, YELLOW))

    def draw_maze(self):
        for y in range(ROWS):
            for x in range(COLS):
                cell = self.maze[y][x]
                px = x * CELL_SIZE + MAZE_OFFSET_X
                py = y * CELL_SIZE + MAZE_OFFSET_Y

                if cell == 1:  # Wall
                    # Draw wall with gradient effect
                    wall_rect = pygame.Rect(px + 1, py + 1, CELL_SIZE - 2, CELL_SIZE - 2)
                    pygame.draw.rect(self.screen, DARK_NAVY, (px, py, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, BLUE, wall_rect, 0, 4)

                    # Inner highlight
                    inner_rect = pygame.Rect(px + 3, py + 3, CELL_SIZE - 6, CELL_SIZE - 6)
                    pygame.draw.rect(self.screen, BRIGHT_BLUE, inner_rect, 1, 3)

                elif cell == 0:  # Dot
                    dot_x = px + CELL_SIZE // 2
                    dot_y = py + CELL_SIZE // 2
                    pygame.draw.circle(self.screen, WHITE, (dot_x, dot_y), 3)
                    # Glow
                    glow_surf = pygame.Surface((10, 10), pygame.SRCALPHA)
                    pygame.draw.circle(glow_surf, (255, 255, 255, 60), (5, 5), 5)
                    self.screen.blit(glow_surf, (dot_x - 5, dot_y - 5))

                elif cell == 2:  # Power pellet
                    dot_x = px + CELL_SIZE // 2
                    dot_y = py + CELL_SIZE // 2
                    pulse = abs(math.sin(self.frame * 0.1)) * 3
                    radius = int(7 + pulse)

                    # Glow
                    glow_surf = pygame.Surface((radius * 4, radius * 4), pygame.SRCALPHA)
                    pygame.draw.circle(glow_surf, (255, 255, 0, 40), (radius * 2, radius * 2), radius * 2)
                    self.screen.blit(glow_surf, (dot_x - radius * 2, dot_y - radius * 2))

                    pygame.draw.circle(self.screen, GOLD, (dot_x, dot_y), radius)
                    pygame.draw.circle(self.screen, WHITE, (dot_x - 2, dot_y - 2), 2)

    def draw_ui(self):
        # Background for UI
        pygame.draw.rect(self.screen, (10, 10, 30), (0, 0, SCREEN_WIDTH, MAZE_OFFSET_Y))
        pygame.draw.rect(self.screen, (10, 10, 30), (0, MAZE_OFFSET_Y + ROWS * CELL_SIZE, SCREEN_WIDTH, 50))

        # Title
        title_surf = self.font_large.render("PAC-MAN", True, YELLOW)
        # Add shadow
        shadow_surf = self.font_large.render("PAC-MAN", True, (100, 100, 0))
        self.screen.blit(shadow_surf, (SCREEN_WIDTH // 2 - title_surf.get_width() // 2 + 2, 7))
        self.screen.blit(title_surf, (SCREEN_WIDTH // 2 - title_surf.get_width() // 2, 5))

        # Score
        score_text = self.font_small.render(f"SCORE: {self.pacman.score}", True, WHITE)
        self.screen.blit(score_text, (20, 45))

        # High score
        if self.pacman.score > self.high_score:
            self.high_score = self.pacman.score
        hi_text = self.font_small.render(f"BEST: {self.high_score}", True, GOLD)
        self.screen.blit(hi_text, (SCREEN_WIDTH // 2 - hi_text.get_width() // 2, 45))

        # Lives
        lives_text = self.font_small.render("LIVES:", True, WHITE)
        self.screen.blit(lives_text, (SCREEN_WIDTH - 200, 45))
        for i in range(self.pacman.lives):
            lx = SCREEN_WIDTH - 120 + i * 30
            ly = 55
            pygame.draw.circle(self.screen, YELLOW, (lx, ly), 10)
            # Mouth
            points = [(lx, ly)]
            for a in range(30, 60):
                rad = math.radians(a)
                points.append((lx + 10 * math.cos(rad), ly + 10 * math.sin(rad)))
            if len(points) > 2:
                pygame.draw.polygon(self.screen, BLACK, points)

        # Power mode indicator
        if self.power_mode:
            power_pct = self.power_timer / 400
            bar_width = 200
            bar_x = SCREEN_WIDTH // 2 - bar_width // 2
            bar_y = MAZE_OFFSET_Y + ROWS * CELL_SIZE + 10

            pygame.draw.rect(self.screen, (50, 50, 50), (bar_x, bar_y, bar_width, 15), 0, 5)
            color = CYAN if power_pct > 0.3 else RED
            pygame.draw.rect(self.screen, color, (bar_x, bar_y, int(bar_width * power_pct), 15), 0, 5)

            power_text = self.font_tiny.render("POWER MODE!", True, CYAN)
            self.screen.blit(power_text, (SCREEN_WIDTH // 2 - power_text.get_width() // 2, bar_y + 18))

    def draw_particles(self):
        self.particles = [p for p in self.particles if p.update()]
        for p in self.particles:
            p.draw(self.screen)

    def draw_score_popups(self):
        new_popups = []
        for popup in self.score_popups:
            popup['timer'] -= 1
            popup['y'] -= 1
            if popup['timer'] > 0:
                alpha = min(255, popup['timer'] * 4)
                text = self.font_small.render(popup['text'], True, popup['color'])
                self.screen.blit(text, (int(popup['x']), int(popup['y'])))
                new_popups.append(popup)
        self.score_popups = new_popups

    def draw_start_screen(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 180))
        self.screen.blit(overlay, (0, 0))

        # Animated title
        scale = 1 + 0.05 * math.sin(self.frame * 0.05)
        title = self.font_large.render("PAC-MAN", True, YELLOW)
        scaled = pygame.transform.scale(title, (int(title.get_width() * scale), int(title.get_height() * scale)))
        self.screen.blit(scaled, (SCREEN_WIDTH // 2 - scaled.get_width() // 2, 150))

        # Blinking start text
        if (self.frame // 30) % 2 == 0:
            start_text = self.font_medium.render("PRESS SPACE TO START", True, WHITE)
            self.screen.blit(start_text, (SCREEN_WIDTH // 2 - start_text.get_width() // 2, 280))

        controls = self.font_small.render("ARROW KEYS or WASD to move", True, LIGHT_BLUE)
        self.screen.blit(controls, (SCREEN_WIDTH // 2 - controls.get_width() // 2, 350))

        # Ghost showcase
        ghost_colors = [RED, PINK, CYAN, ORANGE]
        ghost_names = ['BLINKY', 'PINKY', 'INKY', 'CLYDE']
        for i, (color, name) in enumerate(zip(ghost_colors, ghost_names)):
            gx = 150 + i * 130
            gy = 430

            # Simple ghost drawing
            pygame.draw.circle(self.screen, color, (gx, gy), 20)
            pygame.draw.rect(self.screen, color, (gx - 20, gy, 40, 20))

            # Eyes
            pygame.draw.circle(self.screen, WHITE, (gx - 7, gy - 5), 6)
            pygame.draw.circle(self.screen, WHITE, (gx + 7, gy - 5), 6)
            pygame.draw.circle(self.screen, (0, 0, 200), (gx - 6, gy - 4), 3)
            pygame.draw.circle(self.screen, (0, 0, 200), (gx + 8, gy - 4), 3)

            name_text = self.font_tiny.render(name, True, color)
            self.screen.blit(name_text, (gx - name_text.get_width() // 2, gy + 25))

    def draw_game_over(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 150))
        self.screen.blit(overlay, (0, 0))

        # Pulsing game over text
        pulse = abs(math.sin(self.frame * 0.05))
        color = (int(255 * pulse), 0, 0)

        go_text = self.font_large.render("GAME OVER", True, color)
        self.screen.blit(go_text, (SCREEN_WIDTH // 2 - go_text.get_width() // 2, 200))

        score_text = self.font_medium.render(f"SCORE: {self.pacman.score}", True, YELLOW)
        self.screen.blit(score_text, (SCREEN_WIDTH // 2 - score_text.get_width() // 2, 290))

        if self.pacman.score >= self.high_score:
            hi_text = self.font_small.render("NEW HIGH SCORE!", True, GOLD)
            self.screen.blit(hi_text, (SCREEN_WIDTH // 2 - hi_text.get_width() // 2, 340))

        if (self.frame // 30) % 2 == 0:
            restart_text = self.font_small.render("PRESS SPACE TO PLAY AGAIN", True, WHITE)
            self.screen.blit(restart_text, (SCREEN_WIDTH // 2 - restart_text.get_width() // 2, 400))

    def draw_win_screen(self):
        overlay = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 150))
        self.screen.blit(overlay, (0, 0))

        # Rainbow win text
        colors = [RED, ORANGE, YELLOW, (0, 255, 0), CYAN, BLUE, MAGENTA]
        text = "YOU WIN!"
        for i, char in enumerate(text):
            color = colors[i % len(colors)]
            char_surf = self.font_large.render(char, True, color)
            x = SCREEN_WIDTH // 2 - len(text) * 25 + i * 50
            y = 200 + int(10 * math.sin(self.frame * 0.1 + i * 0.5))
            self.screen.blit(char_surf, (x, y))

        score_text = self.font_medium.render(f"SCORE: {self.pacman.score}", True, YELLOW)
        self.screen.blit(score_text, (SCREEN_WIDTH // 2 - score_text.get_width() // 2, 300))

        if (self.frame // 30) % 2 == 0:
            restart_text = self.font_small.render("PRESS SPACE TO PLAY AGAIN", True, WHITE)
            self.screen.blit(restart_text, (SCREEN_WIDTH // 2 - restart_text.get_width() // 2, 380))

        # Celebration particles
        if self.frame % 5 == 0:
            for _ in range(3):
                px = random.randint(0, SCREEN_WIDTH)
                py = random.randint(0, SCREEN_HEIGHT)
                color = random.choice([RED, YELLOW, CYAN, MAGENTA, ORANGE])
                self.particles.append(Particle(px, py, color))

    def draw_background(self):
        # Gradient background
        self.screen.fill(DARK_NAVY)

        # Subtle grid pattern
        for x in range(0, SCREEN_WIDTH, 40):
            pygame.draw.line(self.screen, (0, 0, 60), (x, 0), (x, SCREEN_HEIGHT), 1)
        for y in range(0, SCREEN_HEIGHT, 40):
            pygame.draw.line(self.screen, (0, 0, 60), (0, y), (SCREEN_WIDTH, y), 1)

    def handle_input(self):
        keys = pygame.key.get_pressed()

        if keys[pygame.K_LEFT] or keys[pygame.K_a]:
            self.pacman.next_direction = (-1, 0)
        elif keys[pygame.K_RIGHT] or keys[pygame.K_d]:
            self.pacman.next_direction = (1, 0)
        elif keys[pygame.K_UP] or keys[pygame.K_w]:
            self.pacman.next_direction = (0, -1)
        elif keys[pygame.K_DOWN] or keys[pygame.K_s]:
            self.pacman.next_direction = (0, 1)

    def update(self):
        self.frame += 1

        if self.state == 'start':
            return

        if self.state == 'dying':
            self.death_timer -= 1
            self.pacman.death_animation = min(1.0, (120 - self.death_timer) / 60)

            if self.death_timer <= 0:
                if self.pacman.lives <= 0:
                    self.state = 'game_over'
                else:
                    self.reset_positions()
                    self.state = 'playing'
            return

        if self.state in ['game_over', 'win']:
            return

        if self.start_timer > 0:
            self.start_timer -= 1
            return

        # Update power mode
        if self.power_mode:
            self.power_timer -= 1
            if self.power_timer <= 0:
                self.power_mode = False
                for ghost in self.ghosts:
                    ghost.scared = False

        # Move pacman every other frame for speed control
        if self.frame % 2 == 0:
            self.move_pacman()

        # Move ghosts every 3 frames
        if self.frame % 3 == 0:
            for ghost in self.ghosts:
                self.move_ghost(ghost)

        # Animate
        self.pacman.animate()
        for ghost in self.ghosts:
            ghost.animate()

        # Check collisions
        self.check_collisions()

        # Check win condition
        if self.dots_eaten >= self.total_dots:
            self.state = 'win'

    def draw(self):
        self.draw_background()
        self.draw_maze()

        # Draw ghosts
        for ghost in self.ghosts:
            ghost.draw(self.screen)

        # Draw pacman
        self.pacman.draw(self.screen)

        self.draw_particles()
        self.draw_score_popups()
        self.draw_ui()

        # Overlay screens
        if self.state == 'start':
            self.draw_start_screen()
        elif self.state == 'game_over':
            self.draw_game_over()
        elif self.state == 'win':
            self.draw_win_screen()
        elif self.state == 'playing' and self.start_timer > 0:
            # Ready text
            ready_text = self.font_medium.render("READY!", True, YELLOW)
            self.screen.blit(ready_text, (SCREEN_WIDTH // 2 - ready_text.get_width() // 2,
                                          MAZE_OFFSET_Y + 16 * CELL_SIZE - 20))

        pygame.display.flip()

    def run(self):
        print("Starting Pac-Man game...")
        print("Controls: Arrow keys or WASD to move")
        print("Press SPACE to start")

        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                elif event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_ESCAPE:
                        running = False
                    elif event.key == pygame.K_SPACE:
                        if self.state == 'start':
                            self.state = 'playing'
                            if START_SOUND:
                                START_SOUND.play()
                        elif self.state in ['game_over', 'win']:
                            self.pacman.score = 0
                            self.pacman.lives = 3
                            self.reset_game()
                            self.state = 'playing'
                            if START_SOUND:
                                START_SOUND.play()

            if self.state == 'playing':
                self.handle_input()

            self.update()
            self.draw()
            self.clock.tick(60)

        pygame.quit()
        print("Game ended. Final score:", self.pacman.score)
        sys.exit()


# Run the game
if __name__ == "__main__":
    game = Game()
    game.run()